import{c as l,$ as h,Q as a,j as c,m as i,h as s,ax as t,n as r,o as d,S as n}from"./chunks/framework.BqPkuuVc.js";const v=JSON.parse('{"title":"Why NLPM is built","description":"","frontmatter":{"title":"Why NLPM is built","outline":[2,3]},"headers":[],"relativePath":"why.md","filePath":"why.md","lastUpdated":1779191486000}'),p={name:"why.md"};function u(m,e,g,f,b,k){const o=h("Mermaid");return a(),c("div",null,[e[2]||(e[2]=i(`<h1 id="why-nlpm-is-built" tabindex="-1">Why NLPM is built <a class="header-anchor" href="#why-nlpm-is-built" aria-label="Permalink to &quot;Why NLPM is built&quot;">​</a></h1><p>NLPM exists because a 69,816-star plugin shipped four invisible skills, and no validator in the ecosystem was going to catch it.</p><p>That sentence is small enough to dismiss. The rest of this page argues why it shouldn&#39;t be.</p><h2 id="the-bug-class-that-keeps-shipping" tabindex="-1">The bug class that keeps shipping <a class="header-anchor" href="#the-bug-class-that-keeps-shipping" aria-label="Permalink to &quot;The bug class that keeps shipping&quot;">​</a></h2><p><code>mattpocock/skills</code> (69.8k stars, MIT-licensed, written by a TypeScript ecosystem figure with a reputation for rigorous tooling) shipped with 13 skills declared in <code>plugin.json</code> and 17 SKILL.md files on disk. The four extras — <code>git-guardrails-claude-code</code>, <code>setup-pre-commit</code>, <code>migrate-to-shoehorn</code>, <code>scaffold-exercises</code> — each had valid frontmatter and worked locally. None of them were reachable after <code>claude plugin install</code>.</p><p>The diff that finds this is mechanical:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">diff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.skills[]&#39; .claude-plugin/plugin.json </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;skills/*/*/SKILL.md&#39; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;s|/SKILL.md||;s|^|./|&#39; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span></span></code></pre></div><p>Five seconds. No judgment. No model needed.</p><p>This isn&#39;t an isolated lapse. The same bug class has shipped in <code>safishamsi/graphify</code> (37k⭐), <code>kubesphere/kubesphere</code> (16k⭐), <code>tanweai/pua</code> (16.7k⭐), and <code>agent-sh/agnix</code> (5k⭐). The maintainers are not careless — they are using the tools that exist for the layer those tools cover. The bug ships because no tool covers <em>this</em> layer.</p><h2 id="what-the-ecosystem-already-has" tabindex="-1">What the ecosystem already has <a class="header-anchor" href="#what-the-ecosystem-already-has" aria-label="Permalink to &quot;What the ecosystem already has&quot;">​</a></h2><p>By 2026-05, there are at least eight SKILL.md / plugin-manifest validators in active development:</p><table tabindex="0"><thead><tr><th>Source</th><th>What it checks</th></tr></thead><tbody><tr><td><code>claude plugin validate</code> (Anthropic, built-in CLI)</td><td>Manifest JSON syntax + deprecation warnings</td></tr><tr><td><code>plugin-validator</code> agent (Anthropic)</td><td>Per-component frontmatter, manifest fields, security, MCP config</td></tr><tr><td><code>skills-ref</code> (Linux Foundation, Python + Rust)</td><td>Per-skill: frontmatter validity, <code>name == parent_dir</code></td></tr><tr><td><code>claude-plugin-validate</code> (situ2001, Rust)</td><td>Manifest schema, frontmatter, hooks JSON</td></tr><tr><td><code>agent-skill-linter</code> (William-Yeh)</td><td>Spec compliance, badges, LICENSE, auto-fix</td></tr><tr><td><code>skill-check</code> (thedaviddias)</td><td>Structure, body limits, description quality, 0–100 score</td></tr><tr><td><code>skill-validator</code> (agent-ecosystem)</td><td>Content density + pre-commit hooks</td></tr><tr><td><code>skill-linter</code> ×2 (majesticlabs, RHEcosystem)</td><td>Marketplace gate logic</td></tr></tbody></table><p>The validators concentrate at the <strong>single-artifact</strong> boundary: does <em>this</em> SKILL.md have a valid <code>name</code>? Does <em>this</em> <code>plugin.json</code> parse? At that layer, eight tools compete and any one of them catches what the others catch.</p><p>The validators avoid the <strong>cross-artifact</strong> boundary: does the array in <code>plugin.json</code> enumerate every SKILL.md on disk? Does every tool in <code>allowed-tools</code> have a call site? Do cross-references resolve?</p><p><code>/nlpm:check</code> is, by current research, the only validator that systematically checks this layer.</p><h2 id="why-the-gap-exists" tabindex="-1">Why the gap exists <a class="header-anchor" href="#why-the-gap-exists" aria-label="Permalink to &quot;Why the gap exists&quot;">​</a></h2><p>Five compounding factors keep the bug class shipping:</p><ol><li><strong>The right validator missing in canonical form.</strong> Manifest-vs-disk isn&#39;t in Anthropic&#39;s official <code>plugin-validator</code>. Authors who reach for &quot;the official tool&quot; don&#39;t get this check.</li><li><strong>Discovery is broken.</strong> Eight tools, no SEO winner, no GitHub Actions template that ships with <code>claude plugin init</code>. Authors don&#39;t know which tool to pick, so most pick none.</li><li><strong>The spec is young.</strong> Anthropic published Agent Skills on 2025-12-18. Five months is not enough time for collective practice to crystallize — TypeScript took about five years to settle on <code>tsc --noEmit</code> + ESLint + <code>tsconfig.json</code> as the canonical local validation stack.</li><li><strong>&quot;Works on my machine&quot; is the testing default.</strong> Authors develop in their own <code>.claude/</code> directory; the runtime walks the filesystem and finds the skill. The bug only surfaces on a fresh install of the published manifest — a code path the author rarely exercises.</li><li><strong>No install-time loud failure.</strong> <code>claude plugin install</code> succeeds with an incomplete manifest. Missing skills are silently invisible. There is no <code>ImportError</code>-equivalent that tells the author what they just published is broken.</li></ol><p>Every successful code ecosystem has at least one install-time or build-time gate that fails loudly on this class of inconsistency:</p><table tabindex="0"><thead><tr><th>Ecosystem</th><th>Forcing function</th></tr></thead><tbody><tr><td>TypeScript / Node</td><td>Missing <code>exports</code> → <code>Cannot find module</code> at runtime</td></tr><tr><td>Python</td><td>Missing <code>entry_points</code> → <code>pkg_resources.DistributionNotFound</code></td></tr><tr><td>Rust</td><td><code>cargo build</code> cross-checks <code>mod</code> against <code>src/</code></td></tr><tr><td>Ruby</td><td><code>gem build</code> rejects gemspecs referencing missing files</td></tr><tr><td>Go</td><td><code>go build</code> and <code>go vet</code> cross-check declared packages against disk</td></tr><tr><td><strong>Claude plugins</strong></td><td>None. Install succeeds with incomplete manifest.</td></tr></tbody></table><p>Plugin authoring doesn&#39;t have that gate yet. NLPM is one attempt to provide it.</p><h2 id="the-deeper-observation" tabindex="-1">The deeper observation <a class="header-anchor" href="#the-deeper-observation" aria-label="Permalink to &quot;The deeper observation&quot;">​</a></h2><p>Patching one missing check would be a small open-source contribution. NLPM is shaped around a bigger claim: <strong>natural-language programs are programs, and a program needs a vocabulary as much as it needs a syntax.</strong></p><p>A SKILL.md isn&#39;t prose. It is a declaration that an executor (Claude, Codex, another agent) will read and act on. When two skills name the same act with different verbs, when an agent says &quot;scan&quot; in one place and &quot;check&quot; three lines later, when a noun-verb pairing exists in one file and the inverted form in another — these aren&#39;t stylistic preferences. They are the NL equivalent of redeclaring a function with a different signature and hoping the linker figures it out.</p><p>This led to the six vocabulary principles (P1–P6)<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>, drawn from OntoClean (Guarino &amp; Welty), Domain-Driven Design (Evans), ISO 25964 / ANSI-NISO Z39.19 warrant theory, and BPMN / Event Storming (Brandolini):</p>`,25)),(a(),s(n,null,{default:t(()=>[d(o,{id:"mermaid-231",class:"mermaid-diagram",graph:"flowchart%20LR%0A%20%20P2%5B%22P2%20%E2%80%94%20nouns%20rigid%3Cbr%2F%3Everbs%20state-changing%22%5D%20--%3E%20P3%5B%22P3%20%E2%80%94%20verb%20only%3Cbr%2F%3Eif%20it%20gates%20or%20produces%22%5D%0A%20%20P3%20--%3E%20P1%5B%22P1%20%E2%80%94%20one%20term%20per%3Cbr%2F%3Eidentity%2C%20within%20scope%22%5D%0A%20%20P1%20--%3E%20P4%5B%22P4%20%E2%80%94%20vocabulary%3Cbr%2F%3Eclosed%20under%20operations%22%5D%0A%20%20P4%20--%3E%20P5%5B%22P5%20%E2%80%94%20no%20unnamed%3Cbr%2F%3Ejudgment%22%5D%0A%20%20P5%20--%3E%20P6%5B%22P6%20%E2%80%94%20warrant%3Cbr%2F%3Ebefore%20entry%22%5D%0A%0A%20%20classDef%20p%20fill%3A%23d5e0ff%2Cstroke%3A%232b5fff%2Ccolor%3A%231d2433%0A%20%20class%20P1%2CP2%2CP3%2CP4%2CP5%2CP6%20p%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[r(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=i('<p>The arrows are precedence — P2 takes precedence over P3, P3 over P1, and so on. The order matters. P6 (warrant) is an entry check, not a veto over terms that satisfy the higher principles, which is why deferred terms in NLPM&#39;s own registry remain deferred rather than rejected.</p><p>These principles power R51 — NLPM&#39;s opt-in vocabulary-drift rule — and the registry-free <code>/nlpm:vocab-drift</code> scan that ships alongside it.</p><h2 id="what-nlpm-is-framed-by-the-gap" tabindex="-1">What NLPM is, framed by the gap <a class="header-anchor" href="#what-nlpm-is-framed-by-the-gap" aria-label="Permalink to &quot;What NLPM is, framed by the gap&quot;">​</a></h2><p>The shape of the tool follows from the two observations above.</p><table tabindex="0"><thead><tr><th>Component</th><th>Why it exists</th></tr></thead><tbody><tr><td><code>/nlpm:check</code></td><td>Cross-artifact validation — the layer no other tool covers</td></tr><tr><td><code>/nlpm:score</code> (51 rules, 100-point)</td><td>Quality scoring grounded in primary-source citations, not house style</td></tr><tr><td><code>/nlpm:vocab-drift</code> + R51</td><td>Vocabulary discipline; opt-in by design</td></tr><tr><td><code>bin/nlpm-check</code> (stdlib-only Python)</td><td>Pre-commit / CI gate that runs without Claude Code</td></tr><tr><td>Auditor pipeline</td><td>Continuous corpus building — the rules get refined by contact with real plugins, not by speculation</td></tr><tr><td>Case studies + exemplars</td><td>Evidence trail; every rule cites real-world examples</td></tr></tbody></table><p>The two pipelines (local for authors, auditor for the corpus) share one rulebook. Findings from the auditor feed <code>rule-health.py</code>. Rules that generate noise get refined. Rules with strong real-world warrant become exemplars that cite back into the rulebook. The loop is closed, and only one step in it (rule refinement) is allowed to mutate the rulebook — and only through a human-reviewed PR.</p><h2 id="how-to-use-it" tabindex="-1">How to use it <a class="header-anchor" href="#how-to-use-it" aria-label="Permalink to &quot;How to use it&quot;">​</a></h2><p>NLPM has five entry points; pick whichever fits the moment of your workflow you want guarded.</p><h3 id="inside-claude-code-—-slash-commands" tabindex="-1">Inside Claude Code — slash commands <a class="header-anchor" href="#inside-claude-code-—-slash-commands" aria-label="Permalink to &quot;Inside Claude Code — slash commands&quot;">​</a></h3><p>Once installed via <code>claude plugin install nlpm@xiaolai --scope project</code>, you get the full surface:</p><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><a href="/reference/"><code>/nlpm:ls</code></a></td><td>Discover every NL artifact in the current repo</td></tr><tr><td><a href="/reference/scoring"><code>/nlpm:score</code></a></td><td>100-point quality scoring against R01–R51</td></tr><tr><td><a href="/install#what-nlpm-check-catches"><code>/nlpm:check</code></a></td><td>Cross-component checks — manifest-vs-disk, broken refs, orphans</td></tr><tr><td><code>/nlpm:fix</code></td><td>Auto-fix mechanical issues (rule numbers, frontmatter, hook event case)</td></tr><tr><td><code>/nlpm:test</code></td><td>Run NL-TDD specs against agents and skills</td></tr><tr><td><code>/nlpm:trend</code></td><td>Track score history over time</td></tr><tr><td><code>/nlpm:report</code></td><td>Self-contained HTML report (per-file scores, trend, vocab map)</td></tr><tr><td><a href="/reference/vocabulary"><code>/nlpm:vocab-init</code></a></td><td>Bootstrap a vocabulary registry for any project</td></tr><tr><td><a href="/reference/drift"><code>/nlpm:vocab-drift</code></a></td><td>Registry-free drift advisory — no commitment required</td></tr><tr><td><code>/nlpm:security-scan</code></td><td>Executable-surface scan (hooks, scripts, MCP, dependencies)</td></tr></tbody></table><p>Slash commands dispatch agents; agents load skills; skills cite rules. The whole stack is markdown — nothing compiles, nothing locks you in.</p><h3 id="on-the-command-line-—-bin-nlpm-check" tabindex="-1">On the command line — <code>bin/nlpm-check</code> <a class="header-anchor" href="#on-the-command-line-—-bin-nlpm-check" aria-label="Permalink to &quot;On the command line — `bin/nlpm-check`&quot;">​</a></h3><p>For environments without Claude Code (CI, pre-commit, release scripts), a single-file Python script (stdlib only, no <code>pip install</code>) runs the deterministic subset:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nlpm-check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># nlpm-check: 17 artifacts · 0 high · 0 medium · 0 low (.)</span></span></code></pre></div><p>Exit code 0 (clean) / 1 (high-confidence findings) / 2 (errors). Works on a 50-artifact plugin in under two seconds. See <a href="/install">the install guide</a> for the curl one-liner.</p><h3 id="at-commit-time-—-pre-commit-hook" tabindex="-1">At commit time — pre-commit hook <a class="header-anchor" href="#at-commit-time-—-pre-commit-hook" aria-label="Permalink to &quot;At commit time — pre-commit hook&quot;">​</a></h3><p>A drop-in template at <a href="https://github.com/xiaolai/nlpm-for-claude/blob/main/templates/pre-commit-nlpm.sh" target="_blank" rel="noreferrer"><code>templates/pre-commit-nlpm.sh</code></a> that calls <code>nlpm-check</code>. Bad commits don&#39;t land — the &quot;loud failure&quot; that the rest of the ecosystem doesn&#39;t provide.</p><h3 id="on-every-pr-—-github-actions" tabindex="-1">On every PR — GitHub Actions <a class="header-anchor" href="#on-every-pr-—-github-actions" aria-label="Permalink to &quot;On every PR — GitHub Actions&quot;">​</a></h3><p>A drop-in workflow at <a href="https://github.com/xiaolai/nlpm-for-claude/blob/main/templates/workflows/nlpm-check.yml" target="_blank" rel="noreferrer"><code>templates/workflows/nlpm-check.yml</code></a> runs the check on every push and pull request. No secrets required; no write scope unless you opt into auto-fix.</p><h3 id="on-your-readme-—-the-validated-by-nlpm-badge" tabindex="-1">On your README — the &quot;Validated by NLPM&quot; badge <a class="header-anchor" href="#on-your-readme-—-the-validated-by-nlpm-badge" aria-label="Permalink to &quot;On your README — the &quot;Validated by NLPM&quot; badge&quot;">​</a></h3><p>The GHA workflow writes a shields.io-compatible JSON to the repo root. Add this line to your README:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">![</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">Validated by NLPM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">https://img.shields.io/endpoint?url=https://raw.githubusercontent.com/YOUR-USER/YOUR-REPO/main/nlpm-badge.json</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>The badge auto-updates each push to <code>main</code>:</p><table tabindex="0"><thead><tr><th>State</th><th>Color</th><th>Message</th></tr></thead><tbody><tr><td>Clean</td><td>green</td><td><code>0 issues · v0.8.x</code></td></tr><tr><td>Advisory</td><td>yellow</td><td><code>0 high · N advisory</code></td></tr><tr><td>Failing</td><td>red</td><td><code>N high issues</code></td></tr></tbody></table><p>It is a public, machine-readable claim: &quot;this plugin currently passes NLPM&#39;s cross-component checks at the SHA the badge points to.&quot;</p><h3 id="as-a-consumer-—-the-auditor-dashboard" tabindex="-1">As a consumer — the auditor dashboard <a class="header-anchor" href="#as-a-consumer-—-the-auditor-dashboard" aria-label="Permalink to &quot;As a consumer — the auditor dashboard&quot;">​</a></h3><p>If you are evaluating a plugin you didn&#39;t write, the <a href="/dashboard">cross-repo dashboard</a> shows NLPM&#39;s audit of 200+ public Claude Code plugins — score, security gate, vocabulary drift, and the per-finding evidence trail. Each repo links to a full audit report with the exact line numbers of every issue.</p><h2 id="the-corpus-as-of-today" tabindex="-1">The corpus, as of today <a class="header-anchor" href="#the-corpus-as-of-today" aria-label="Permalink to &quot;The corpus, as of today&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Count</th></tr></thead><tbody><tr><td>Repos audited</td><td>210</td></tr><tr><td>Case studies written</td><td>28</td></tr><tr><td>Exemplars cited in the rulebook</td><td>62</td></tr><tr><td>Rules in the rulebook</td><td>51</td></tr><tr><td>Vocabulary principles</td><td>6</td></tr><tr><td>NLPM&#39;s own self-audit score</td><td>100 / 100</td></tr></tbody></table><p>The corpus is what makes the rules trustable. A rule with no examples in the wild is a hypothesis; a rule with a dozen exemplars is a codified observation. The auditor pipeline is the mechanism that converts the first into the second.</p><h2 id="how-it-evolves" tabindex="-1">How it evolves <a class="header-anchor" href="#how-it-evolves" aria-label="Permalink to &quot;How it evolves&quot;">​</a></h2><p>NLPM is 8 weeks old. The first commit landed 2026-03-25; the current release is v0.8.22. In between: 1,287 commits, five minor-version gates (v0.2 → v0.4 → v0.6 → v0.7 → v0.8), and 22 patch releases since v0.8.0 alone. The cadence is high because the rules keep getting proven wrong by contact with real repositories — and the project&#39;s shape is built to absorb that.</p><h3 id="the-feedback-loop" tabindex="-1">The feedback loop <a class="header-anchor" href="#the-feedback-loop" aria-label="Permalink to &quot;The feedback loop&quot;">​</a></h3>',34)),(a(),s(n,null,{default:t(()=>[d(o,{id:"mermaid-586",class:"mermaid-diagram",graph:"flowchart%20LR%0A%20%20Audit%5Bauditor-audit%5D%20--%3E%20Findings%5Bfindings.jsonl%5D%0A%20%20Findings%20--%3E%20Contribute%5Bcontribute%20PR%5D%0A%20%20Contribute%20--%3E%20Maintainer%5Bmaintainer%20reaction%5D%0A%20%20Maintainer%20--%3E%7Cmerged%7C%20Verified%5Bfinding_verified%5D%0A%20%20Maintainer%20--%3E%7Crejected%7C%20Disputed%5Bpr_comments_snapshot%5D%0A%20%20Verified%20--%3E%20Health%5Brule-health.py%5D%0A%20%20Disputed%20--%3E%20Health%0A%20%20Health%20--%3E%7C%22noisy%20%2F%20disputed%20%2F%20dormant%22%7C%20Refine%5Brefine-rules%20PR%5D%0A%20%20Refine%20--%3E%7Chuman%20review%7C%20Rulebook%5Bskills%2Fnlpm%2Frules%5D%0A%20%20Rulebook%20-.next%20audit.-%3E%20Audit%0A%0A%20%20classDef%20auto%20fill%3A%23d5e0ff%2Cstroke%3A%232b5fff%2Ccolor%3A%231d2433%0A%20%20classDef%20gate%20fill%3A%23fffbf0%2Cstroke%3A%23c47c00%2Ccolor%3A%231d2433%0A%20%20class%20Audit%2CFindings%2CContribute%2CMaintainer%2CVerified%2CDisputed%2CHealth%20auto%0A%20%20class%20Refine%2CRulebook%20gate%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[r(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=i('<p>Everything before <em>refine rules</em> is automated observation. Only the rule-refinement PR is allowed to mutate the rulebook, and only with a human reviewer. That single human-gated step is what stops the loop from amplifying its own noise.</p><h3 id="what-the-commit-log-shows" tabindex="-1">What the commit log shows <a class="header-anchor" href="#what-the-commit-log-shows" aria-label="Permalink to &quot;What the commit log shows&quot;">​</a></h3><p>The pattern is visible in the version history. A few representative commits:</p><table tabindex="0"><thead><tr><th>Commit</th><th>What changed</th><th>Why</th></tr></thead><tbody><tr><td><code>v0.7.15</code></td><td>Tightened <code>BUG-missing-frontmatter</code> scope, pre-filtered security FPs</td><td>Auditor was flagging benign cases as critical</td></tr><tr><td><code>v0.7.22</code></td><td>Cleared 3 of 4 noisy rules — <code>CC-stale-count</code>, demoted <code>SEC-unpinned-semver</code></td><td>Rule-health classified them as noisy after maintainer pushback</td></tr><tr><td><code>v0.7.24</code></td><td>Rebased scoring on the agent-skills.io open standard</td><td>Anthropic&#39;s name-on-commands optionality contradicted an in-house assumption</td></tr><tr><td><code>v0.7.30</code></td><td>Cited <code>code.claude.com/docs</code> as primary source for the name-on-commands rule</td><td>Repeat regression — pinned to the canonical doc, not derived knowledge</td></tr><tr><td><code>v0.7.31</code></td><td>4-layer system to keep NLPM in sync with Claude Code docs</td><td>Stop the spec drift class entirely</td></tr><tr><td><code>v0.7.34</code></td><td>Scorer marks manifest-vs-disk diffs as <code>confidence: high</code></td><td>Memory note: these are deterministic, never speculative</td></tr><tr><td><code>v0.8.0</code></td><td>Standalone <code>bin/nlpm-check</code> binary + author-side templates</td><td>Audit research showed pre-commit gates were what authors needed</td></tr><tr><td><code>v0.8.17</code></td><td>Exemplar pipeline — clean high-scoring audits become teaching artifacts</td><td>Positive warrant, not just negative findings</td></tr></tbody></table><p>None of these were ideas I had at the start. Each one is a response to evidence the auditor produced.</p><h3 id="the-artifacts-that-drive-the-loop" tabindex="-1">The artifacts that drive the loop <a class="header-anchor" href="#the-artifacts-that-drive-the-loop" aria-label="Permalink to &quot;The artifacts that drive the loop&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Artifact</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://github.com/xiaolai/nlpm-for-claude/blob/main/auditor/findings.jsonl" target="_blank" rel="noreferrer"><code>auditor/findings.jsonl</code></a></td><td>One record per finding, joined by deterministic fingerprint</td></tr><tr><td><a href="https://github.com/xiaolai/nlpm-for-claude/blob/main/auditor/disagreements.jsonl" target="_blank" rel="noreferrer"><code>auditor/disagreements.jsonl</code></a></td><td>Maintainer pushback, classifier output, self-flagged false positives</td></tr><tr><td><a href="https://github.com/xiaolai/nlpm-for-claude/blob/main/auditor/logs/events.jsonl" target="_blank" rel="noreferrer"><code>auditor/logs/events.jsonl</code></a></td><td>Lifecycle events — <code>finding_outcome</code>, <code>finding_verified</code>, <code>findings_aggregated</code></td></tr><tr><td><a href="https://github.com/xiaolai/nlpm-for-claude/blob/main/auditor/scripts/rule-health.py" target="_blank" rel="noreferrer"><code>auditor/scripts/rule-health.py</code></a></td><td>Classifies every rule as <code>healthy / noisy / disputed / dormant</code></td></tr><tr><td><code>auditor-refine-rules.yml</code> workflow</td><td>Weekly cron opens a PR with proposed rule edits; nothing merges without human review</td></tr></tbody></table><p>The rules in <code>skills/nlpm/rules/SKILL.md</code> cite specific exemplars and case studies; the case studies link back to the merged PRs; the merged PRs link back to the audits that found the issue. The chain goes both ways. A rule with no evidence in the chain is a candidate for refinement or removal.</p><h2 id="the-wager" tabindex="-1">The wager <a class="header-anchor" href="#the-wager" aria-label="Permalink to &quot;The wager&quot;">​</a></h2><p>Three things could falsify the whole project:</p><ol><li><strong>Anthropic adds manifest-vs-disk to the official <code>plugin-validator</code>.</strong> This would erase NLPM&#39;s headline differentiation overnight. Probability: moderate; timeline: unknown. The mitigation is that the audit corpus and the rule-health feedback loop are the durable asset, not the single check.</li><li><strong>The ecosystem converges on one third-party validator.</strong> Unlikely in the 5-month timeframe but possible by 2027. Today&#39;s fragmentation is the opportunity.</li><li><strong>Authors don&#39;t care.</strong> If the bug class doesn&#39;t bother maintainers enough to install a hook, adoption stays at zero.</li></ol><p>Joint probability of meaningful adoption: somewhere in the 20–35% range, by honest accounting. The asymmetry is the case for shipping anyway. Cost of being wrong: a couple of templates and a Python script. Cost of being right and nobody else covering the gap: thousands of plugins keep shipping with invisible bugs.</p><p>NLPM is the bet that the gap is worth filling, that vocabulary discipline is worth naming, and that a corpus of real audits will outlast any single rule.</p><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p>The principles document lives at <a href="https://github.com/xiaolai/nlpm-for-claude/blob/main/analysis/vocabulary-design-principles.md" target="_blank" rel="noreferrer"><code>analysis/vocabulary-design-principles.md</code></a> in the repository, with the full precedence rationale and the OntoClean / DDD / ISO 25964 / BPMN derivation. The shorter web-facing version is at <a href="/reference/principles">/reference/principles</a>. <a href="#fnref1" class="footnote-backref">↩︎</a></p></li></ol></section>',15))])}const w=l(p,[["render",u]]);export{v as __pageData,w as default};
